// Parse arXiv XML response and extract paper metadata
const items = $input.all();
const results = [];

for (const item of items) {
  // Get the XML response from the HTTP Request node
  const xmlResponse = item.json.body || item.json;

  // Get original form inputs
  const paperTitle = item.json.Paper_Title || '';
  const abstract = item.json.Abstract || '';
  const researchKeywords = item.json.Research_Keywords || '';

  // Parse XML to extract entries
  const entries = [];

  // Simple XML parsing for arXiv feed entries
  const entryMatches = xmlResponse.matchAll(/<entry>(.*?)<\/entry>/gs);

  for (const match of entryMatches) {
    const entry = match[1];

    // Extract title
    const titleMatch = entry.match(/<title>(.*?)<\/title>/s);
    const title = titleMatch ? titleMatch[1].trim().replace(/\n/g, ' ') : '';

    // Extract authors
    const authorMatches = entry.matchAll(/<author>.*?<name>(.*?)<\/name>.*?<\/author>/gs);
    const authors = [];
    for (const authorMatch of authorMatches) {
      authors.push(authorMatch[1].trim());
    }

    // Extract abstract/summary
    const summaryMatch = entry.match(/<summary>(.*?)<\/summary>/s);
    const abstractText = summaryMatch ? summaryMatch[1].trim().replace(/\n/g, ' ') : '';

    // Extract published date
    const publishedMatch = entry.match(/<published>(.*?)<\/published>/);
    const publishedDate = publishedMatch ? publishedMatch[1].trim() : '';
    const year = publishedDate ? new Date(publishedDate).getFullYear() : '';

    // Extract arXiv ID from the id field
    const idMatch = entry.match(/<id>(.*?)<\/id>/);
    const arxivUrl = idMatch ? idMatch[1].trim() : '';
    const arxivIdMatch = arxivUrl.match(/arxiv\.org\/abs\/(.*?)$/);
    const arxivId = arxivIdMatch ? arxivIdMatch[1] : '';

    // Create structured reference object
    entries.push({
      title: title,
      authors: authors,
      year: year,
      abstract: abstractText,
      arxivId: arxivId,
      url: arxivUrl
    });
  }

  // Return formatted output with references and original form data
  results.push({
    json: {
      Paper_Title: paperTitle,
      Abstract: abstract,
      Research_Keywords: researchKeywords,
      references: entries
    }
  });
}

return results;

