// Assemble all paper sections from the orchestrator output
const items = $input.all();

// Extract the agent output from the first item
const agentOutput = items[0].json;

// Extract all sections from the agent output
const paperTitle = agentOutput.paperTitle || 'Untitled Research Paper';
const abstract = agentOutput.abstract || '';
const introduction = agentOutput.introduction || '';
const relatedWork = agentOutput.relatedWork || '';
const methodology = agentOutput.methodology || '';
const results = agentOutput.results || '';
const discussion = agentOutput.discussion || '';
const conclusion = agentOutput.conclusion || '';

// Combine sections into a single structured document with proper headings
const paperContent = `${paperTitle}

` +
  `Abstract\n${abstract}\n\n` +
  `1. Introduction\n${introduction}\n\n` +
  `2. Related Work\n${relatedWork}\n\n` +
  `3. Methodology\n${methodology}\n\n` +
  `4. Results\n${results}\n\n` +
  `5. Discussion\n${discussion}\n\n` +
  `6. Conclusion\n${conclusion}`;

// Return assembled paper content
return [
  {
    json: {
      paperContent: paperContent,
      paperTitle: paperTitle,
      sections: {
        abstract: abstract,
        introduction: introduction,
        relatedWork: relatedWork,
        methodology: methodology,
        results: results,
        discussion: discussion,
        conclusion: conclusion
      }
    }
  }
];

// Generate formatted bibliography from all collected references
// Combine arXiv references and additional references from research agent
// Format each reference in APA style with authors, year, title, source, and URL
// Sort references alphabetically by first author's last name

const references = [];

// Process all input items to collect references
for (const item of $input.all()) {
  // Check for arXiv references
  if (item.json.arxiv_references && Array.isArray(item.json.arxiv_references)) {
    references.push(...item.json.arxiv_references);
  }

  // Check for additional references from research agent
  if (item.json.references && Array.isArray(item.json.references)) {
    references.push(...item.json.references);
  }

  // Check for individual reference fields
  if (item.json.reference) {
    references.push(item.json.reference);
  }
}

// Function to format a single reference in APA style
function formatAPAReference(ref) {
  let formatted = '';

  // Format authors
  if (ref.authors && Array.isArray(ref.authors) && ref.authors.length > 0) {
    if (ref.authors.length === 1) {
      formatted += ref.authors[0];
    } else if (ref.authors.length === 2) {
      formatted += `${ref.authors[0]}, & ${ref.authors[1]}`;
    } else {
      const lastAuthor = ref.authors[ref.authors.length - 1];
      const otherAuthors = ref.authors.slice(0, -1).join(', ');
      formatted += `${otherAuthors}, & ${lastAuthor}`;
    }
  } else if (ref.author) {
    formatted += ref.author;
  }

  // Add year
  if (ref.year) {
    formatted += ` (${ref.year}).`;
  } else if (ref.published) {
    const year = new Date(ref.published).getFullYear();
    formatted += ` (${year}).`;
  } else {
    formatted += ' (n.d.).';
  }

  // Add title
  if (ref.title) {
    formatted += ` ${ref.title}.`;
  }

  // Add source/journal
  if (ref.source) {
    formatted += ` ${ref.source}.`;
  } else if (ref.journal) {
    formatted += ` ${ref.journal}.`;
  } else if (ref.arxiv_id) {
    formatted += ` arXiv preprint arXiv:${ref.arxiv_id}.`;
  }

  // Add URL
  if (ref.url) {
    formatted += ` Retrieved from ${ref.url}`;
  } else if (ref.arxiv_id) {
    formatted += ` Retrieved from https://arxiv.org/abs/${ref.arxiv_id}`;
  }

  return formatted;
}

// Function to extract first author's last name for sorting
function getFirstAuthorLastName(ref) {
  let firstAuthor = '';

  if (ref.authors && Array.isArray(ref.authors) && ref.authors.length > 0) {
    firstAuthor = ref.authors[0];
  } else if (ref.author) {
    firstAuthor = ref.author;
  }

  // Extract last name (assuming format "Last, F." or "First Last")
  if (firstAuthor.includes(',')) {
    return firstAuthor.split(',')[0].trim().toLowerCase();
  } else {
    const parts = firstAuthor.trim().split(' ');
    return parts[parts.length - 1].toLowerCase();
  }
}

// Remove duplicates based on title
const uniqueReferences = [];
const seenTitles = new Set();

for (const ref of references) {
  const title = (ref.title || '').toLowerCase().trim();
  if (title && !seenTitles.has(title)) {
    seenTitles.add(title);
    uniqueReferences.push(ref);
  }
}

// Sort references alphabetically by first author's last name
uniqueReferences.sort((a, b) => {
  const nameA = getFirstAuthorLastName(a);
  const nameB = getFirstAuthorLastName(b);
  return nameA.localeCompare(nameB);
});

// Format all references
const formattedReferences = uniqueReferences.map(ref => formatAPAReference(ref));

// Create bibliography text
const bibliography = formattedReferences.join('\n\n');

// Return the formatted bibliography
return [{
  json: {
    bibliography: bibliography,
    reference_count: formattedReferences.length,
    references: formattedReferences
  }
}];

// Format complete paper as DOCX-compatible content
// Combines paper content and bibliography into structured academic format

const items = $input.all();

// Extract paper content from first input (from Combine Paper and Bibliography node)
const paperData = items[0].json;
const paperContent = paperData.paperContent || {};
const bibliography = paperData.bibliography || '';

// Extract metadata
const title = paperContent.title || 'Research Paper';
const authors = paperContent.authors || 'Author Name';
const affiliation = paperContent.affiliation || 'Institution';
const abstractText = paperContent.abstract || '';
const keywords = paperContent.keywords || '';

// Extract sections
const introduction = paperContent.introduction || '';
const relatedWork = paperContent.relatedWork || '';
const methodology = paperContent.methodology || '';
const results = paperContent.results || '';
const discussion = paperContent.discussion || '';
const conclusion = paperContent.conclusion || '';

// Build formatted DOCX content with proper academic structure
let docxContent = '';

// Title Page
docxContent += `${title}\n\n`;
docxContent += `${authors}\n`;
docxContent += `${affiliation}\n\n`;
docxContent += `---\n\n`;

// Abstract
if (abstractText) {
  docxContent += `ABSTRACT\n\n`;
  docxContent += `${abstractText}\n\n`;
}

// Keywords
if (keywords) {
  docxContent += `Keywords: ${keywords}\n\n`;
}

docxContent += `---\n\n`;

// Main Sections
if (introduction) {
  docxContent += `1. INTRODUCTION\n\n`;
  docxContent += `${introduction}\n\n`;
}

if (relatedWork) {
  docxContent += `2. RELATED WORK\n\n`;
  docxContent += `${relatedWork}\n\n`;
}

if (methodology) {
  docxContent += `3. METHODOLOGY\n\n`;
  docxContent += `${methodology}\n\n`;
}

if (results) {
  docxContent += `4. RESULTS\n\n`;
  docxContent += `${results}\n\n`;
}

if (discussion) {
  docxContent += `5. DISCUSSION\n\n`;
  docxContent += `${discussion}\n\n`;
}

if (conclusion) {
  docxContent += `6. CONCLUSION\n\n`;
  docxContent += `${conclusion}\n\n`;
}

// References/Bibliography
if (bibliography) {
  docxContent += `---\n\n`;
  docxContent += `REFERENCES\n\n`;
  docxContent += `${bibliography}\n`;
}

// Return formatted content
return [
  {
    json: {
      docxContent: docxContent,
      title: title,
      authors: authors,
      sections: {
        introduction: !!introduction,
        relatedWork: !!relatedWork,
        methodology: !!methodology,
        results: !!results,
        discussion: !!discussion,
        conclusion: !!conclusion
      },
      hasBibliography: !!bibliography,
      contentLength: docxContent.length
    }
  }
];
